# Resource Documentation: https://registry.terraform.io/providers/hashicorp/aws/latest/docs/resources/s3_bucket
resource "aws_s3_bucket" "{{bucket_name}}" {
  bucket        = var.bucket_name
  force_destroy = var.force_destroy
  tags          = var.tags
}

resource "aws_s3_bucket_public_access_block" "{{bucket_name}}" {
  bucket                  = aws_s3_bucket.{{bucket_name}}.id
  block_public_acls       = var.block_public_access
  block_public_policy     = var.block_public_access
  ignore_public_acls      = var.block_public_access
  restrict_public_buckets = var.block_public_access
}

resource "aws_s3_bucket_versioning" "{{bucket_name}}" {
  bucket = aws_s3_bucket.{{bucket_name}}.id
  versioning_configuration {
    status = var.enable_versioning ? "Enabled" : "Suspended"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "{{bucket_name}}" {
  bucket = aws_s3_bucket.{{bucket_name}}.id
  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm     = var.kms_key_arn != null ? "aws:kms" : var.sse_algorithm
      kms_master_key_id = var.kms_key_arn
    }
    bucket_key_enabled = var.kms_key_arn != null
  }
}

resource "aws_s3_bucket_ownership_controls" "{{bucket_name}}" {
  bucket = aws_s3_bucket.{{bucket_name}}.id
  rule {
    object_ownership = var.object_ownership
  }
}

resource "aws_s3_bucket_cors_configuration" "{{bucket_name}}" {
  count  = var.enable_cors ? 1 : 0
  bucket = aws_s3_bucket.{{bucket_name}}.id
  cors_rule {
    allowed_headers = var.cors_allowed_headers
    allowed_methods = var.cors_allowed_methods
    allowed_origins = var.cors_allowed_origins
    expose_headers  = var.cors_expose_headers
    max_age_seconds = var.cors_max_age_seconds
  }
}

resource "aws_s3_bucket_logging" "{{bucket_name}}" {
  count         = var.enable_logging ? 1 : 0
  bucket        = aws_s3_bucket.{{bucket_name}}.id
  target_bucket = var.logging_target_bucket
  target_prefix = var.logging_target_prefix
}

resource "aws_s3_bucket_lifecycle_configuration" "{{bucket_name}}" {
  count      = var.enable_lifecycle ? 1 : 0
  bucket     = aws_s3_bucket.{{bucket_name}}.id
  depends_on = [aws_s3_bucket_versioning.{{bucket_name}}]
  rule {
    id     = "cleanup-rule"
    status = "Enabled"
    expiration {
      days = var.lifecycle_expiration_days
    }
    noncurrent_version_expiration {
      noncurrent_days = var.lifecycle_noncurrent_expiration_days
    }
    abort_incomplete_multipart_upload {
      days_after_initiation = var.lifecycle_abort_incomplete_days
    }
  }
}
